final:
module mux_4to1 (
    input wire [3:0] input_data,
    input wire [1:0] sel,
    output wire data_out
);

    assign data_out = (sel == 2'b00) ? input_data[0] :
                      (sel == 2'b01) ? input_data[1] :
                      (sel == 2'b10) ? input_data[2] :
                                       input_data[3];

endmodule
